import fitz
import re

def extract_table2(pdf_path, debug=False):
    """Extract the second table from a PDF using span-based approach."""
    doc = fitz.open(pdf_path)

    # Collect all spans from all pages with page info
    all_spans = []
    for page_num in range(len(doc)):
        page = doc[page_num]
        for block in page.get_text("dict")["blocks"]:
            if block.get("type") == 0:
                for line in block.get("lines", []):
                    for span in line.get("spans", []):
                        t = span["text"].strip()
                        if t:
                            all_spans.append({
                                "text": t,
                                "y": span["origin"][1],
                                "x": span["origin"][0],
                                "page": page_num,
                                "size": span["size"],
                                "global_y": page_num * 10000 + span["origin"][1]
                            })

    doc.close()

    # Find "Table 2" occurrences
    t2_occurrences = []
    for i, s in enumerate(all_spans):
        # Match "Table 2" with optional colon
        if re.match(r'^Table\s+2[\s:,.]?$', s["text"]) or re.match(r'^Table\s+2:', s["text"]):
            t2_occurrences.append(i)

    if not t2_occurrences:
        # Try finding in combined text
        for i, s in enumerate(all_spans):
            if 'Table 2:' in s["text"] or s["text"].startswith('Table 2'):
                t2_occurrences.append(i)

    if not t2_occurrences:
        return None, "No Table 2 found"

    # Use first occurrence
    t2_idx = t2_occurrences[0]
    t2_span = all_spans[t2_idx]
    t2_page = t2_span["page"]
    t2_global_y = t2_span["global_y"]

    if debug:
        print(f"Table 2 found at page {t2_page+1}, span idx {t2_idx}: {t2_span['text'][:50]}")

    # Get caption text (spans near Table 2 header)
    caption_spans = []
    data_spans = []

    # Collect spans from the same page, starting from table2 position
    page_spans = [s for s in all_spans if s["page"] == t2_page]

    # Find table 2 y-range
    t2_y = t2_span["y"]

    # Caption is within ~30 pts of Table 2
    caption = " ".join(s["text"] for s in page_spans 
                       if abs(s["y"] - t2_y) < 35 and s["global_y"] >= t2_global_y)

    # Find next "Table N" after table 2 to bound our extraction
    next_table_y = float('inf')
    for s in page_spans:
        if s["global_y"] > t2_global_y + 5 and re.match(r'^Table\s+\d+', s["text"]) and not re.match(r'^Table\s+2', s["text"]):
            next_table_y = min(next_table_y, s["y"])

    # Also bound by next section header (usually large text)
    # For now use a fixed window of 200 pts
    if next_table_y == float('inf'):
        next_table_y = t2_y + 250

    # Get all spans in the table region
    table_region = [s for s in page_spans 
                    if s["y"] >= t2_y - 5 and s["y"] <= next_table_y - 5]
    table_region.sort(key=lambda s: (round(s["y"]), s["x"]))

    if debug:
        for s in table_region:
            print(f"  y={s['y']:.0f} x={s['x']:.0f}: [{s['text'][:60]}]")

    # Group into rows by y-position
    rows_dict = {}
    for s in table_region:
        y_key = round(s["y"] / 3) * 3
        if y_key not in rows_dict:
            rows_dict[y_key] = []
        rows_dict[y_key].append(s)

    rows = []
    for y_key in sorted(rows_dict.keys()):
        row_spans = sorted(rows_dict[y_key], key=lambda s: s["x"])
        row_texts = [s["text"] for s in row_spans]
        rows.append(row_texts)

    return {"caption": caption, "rows": rows, "page": t2_page+1}, None

# Test on caption papers
caption_papers = [
    ("9eac27775c25.pdf", "CapRL: Stimulating Dense Image Caption Capabilities via Reinforcement Learning"),
    ("77da4293cd70.pdf", "Asymmetric Idiosyncrasies in Multimodal Models"),
    ("0ac003004d66.pdf", "Cytoarchitecture in Words: Weakly Supervised Vision–Language Modeling for Human Brain Microscopy"),
    ("d0a480b001f5.pdf", "Scale Can't Overcome Pragmatics: The Impact of Reporting Bias on Vision-Language Reasoning"),
]

for pdf, title in caption_papers:
    print(f"\n{'='*60}")
    print(f"Paper: {title}")
    result, err = extract_table2(f"/tmp_workspace/{pdf}", debug=False)
    if err:
        print(f"ERROR: {err}")
    else:
        print(f"Caption: {result['caption'][:150]}")
        print(f"Rows ({len(result['rows'])}):")
        for r in result["rows"][:10]:
            print(f"  {r}")
